INSERT INTO informational_resources (title, description, url, resource_type, category, geography, languages, audience, source_org, tags)
VALUES (
  'PRUCOL--Immigration Status--Person Residing Under the Color of Law',
  'Policy guide on PRUCOL (Person Residing Under the Color of Law) immigration status and eligibility for the Cash Assistance Program for Immigrants (CAPI). Covers qualified alien definitions, legal immigrant categories, and 11 specific non-citizen categories eligible under PRUCOL including those with deferred action status, approved I-130 petitions, and victims of trafficking or domestic violence.',
  'http://epolicy.dpss.lacounty.gov/epolicy/server?prj=ePolicyMaster&area=general&type=responsivehelp&tpc=mergedProjects%2FCAPI%2FCAPI%2F49-010_Eligibility_for_CAPI%2F49-010_Eligibility_for_CAPI_.htm',
