INSERT INTO informational_resources (title, description, url, resource_type, category, geography, languages, audience, source_org, tags)
VALUES (
  'California Access to Justice Commission--Supplemental Legal Aid Funding for Vulnerable Populations',
  'California Access to Justice Commission (CALATJ) supplemental legal aid funding for vulnerable populations including immigrants and LGBTQ+ community. $4,875,000 available to nonprofits providing civil legal services. Grants range from $25,000-$150,000 per project. Priorities include protecting constitutional and legal rights of immigrants facing detention and strengthening cybersecurity for legal services programs.',
  'https://calatj.org/grants/funding-for-vulnerable-populations',
  'guide',
  'Legal Services',
